__kernel void hotspotOpt1(__global const float *pIn,
                          __global float *tIn,
                          __global float *tOut,
                          const float stepDivCap,
                          const int numCols,
                          const int numRows,
                          const int layers,
                          const float ce,
                          const float cw,
                          const float cn,
                          const float cs,
                          const float ct,
                          const float cb,
                          const float cc)
{
    if (get_global_id(0) != 0 || get_global_id(1) != 0)
        return;

    const float amb_temp = 80.0f;
    int x, y, z;

    for (z = 0; z < layers; z++) {
        for (y = 0; y < numRows; y++) {
            for (x = 0; x < numCols; x++) {
                int c = x + y * numCols + z * numCols * numRows;

                int w = (x == 0) ? c : c - 1;
                int e = (x == numCols - 1) ? c : c + 1;
                int n = (y == 0) ? c : c - numCols;
                int s = (y == numRows - 1) ? c : c + numCols;
                int b = (z == 0) ? c : c - numCols * numRows;
                int t = (z == layers - 1) ? c : c + numCols * numRows;

                tOut[c] = cc * tIn[c]
                        + cw * tIn[w]
                        + ce * tIn[e]
                        + cn * tIn[n]
                        + cs * tIn[s]
                        + cb * tIn[b]
                        + ct * tIn[t]
                        + stepDivCap * pIn[c]
                        + ct * amb_temp;
            }
        }
    }

    {
        int total = numCols * numRows * layers;
        int i;
        for (i = 0; i < total; i++) {
            tIn[i] = tOut[i];
        }
    }
}
